#!/usr/bin/env node

const fs = require('fs');

// Read the vault audit file
const auditData = fs.readFileSync('./vault-audit.txt', 'utf8');

// Parse the key-value pairs
const keyValuePairs = {};
const lines = auditData.split('\n');

lines.forEach(line => {
  // Skip comments and empty lines
  if (line.trim() && !line.startsWith('#')) {
    const [key, value] = line.split('=');
    if (key && value) {
      keyValuePairs[key.trim()] = value.trim();
    }
  }
});

// Create the JSON payload
const payload = {
  audit_data: keyValuePairs,
  source: 'security_review'
};

// Send to vault service
const https = require('https');

const postData = JSON.stringify(payload);

const options = {
  hostname: 'localhost',
  port: 3003,
  path: '/api/vault-check',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Content-Length': Buffer.byteLength(postData)
  }
};

const req = https.request(options, (res) => {
  console.log(`Status: ${res.statusCode}`);
  console.log(`Headers: ${JSON.stringify(res.headers)}`);

  res.on('data', (chunk) => {
    console.log(`Body: ${chunk.toString()}`);
  });
});

req.on('error', (e) => {
  console.error('Problem with request:', e.message);
});

req.write(postData);
req.end();

